"""
auth.py — JWT authentication layer for the DOMINATE 3AI platform.

Responsibilities
----------------
* User store        : SQLite (users + password reset codes), stdlib only
* Password hashing  : bcrypt (never plaintext)
* Session tokens    : PyJWT, signed + time-limited (exp)
* Persistence       : optional cookie (extra-streamlit-components) so a browser
                      refresh keeps the user logged in. Degrades gracefully to
                      session-only if the package isn't installed.
* UI                : render_login()  -> logo + Sign In, with Sign Up and
                      Forgot Password below the login section.

Secrets (.streamlit/secrets.toml)
---------------------------------
    [auth]
    jwt_secret = "a-long-random-string"      # REQUIRED in production
    token_hours = 12                          # optional, default 12

    [email]                                   # reused for password-reset codes
    smtp_server  = "smtp.gmail.com"
    smtp_port    = 587
    sender       = "you@gmail.com"
    app_password = "your-16-char-app-password"
"""

from __future__ import annotations

import os
import re
import base64
import sqlite3
import secrets as _secrets
from datetime import datetime, timedelta, timezone

import bcrypt
import jwt
import streamlit as st

# Optional cookie persistence ------------------------------------------------
try:
    import extra_streamlit_components as stx
    _HAS_COOKIES = True
except Exception:
    _HAS_COOKIES = False

# ── Config ──────────────────────────────────────────────────────────────────
DB_PATH = os.path.join(os.path.dirname(os.path.abspath(__file__)), "users.db")
COOKIE_NAME = "d3ai_token"
ALGO = "HS256"
EMAIL_RE = re.compile(r"^[^@\s]+@[^@\s]+\.[^@\s]+$")

# Logo asset — drop this PNG next to auth.py / app_finalv3.py
LOGO_FILENAME = "D3ai_logo.png"

# Embedded copy of the brand logo (base64). Used as a fallback so the login
# page and sidebar always show the wordmark image even when the PNG above is
# not deployed next to this file. A real file at LOGO_FILENAME still wins.
_EMBEDDED_LOGO_URI = "data:image/png;base64,"


@st.cache_data(show_spinner=False)
def get_logo_data_uri():
    """Return the logo as a base64 data URI (inlined so it works regardless of
    static-file serving / deployment path). Returns None if the file is missing,
    so callers can fall back to the text wordmark."""
    path = os.path.join(os.path.dirname(os.path.abspath(__file__)), LOGO_FILENAME)
    try:
        with open(path, "rb") as f:
            b64 = base64.b64encode(f.read()).decode("ascii")
        return f"data:image/png;base64,{b64}"
    except Exception:
        # Fall back to the embedded wordmark so the image still shows.
        return _EMBEDDED_LOGO_URI


def _jwt_secret() -> str:
    """Prefer secrets.toml; fall back to a generated per-process key (dev only)."""
    try:
        return st.secrets["auth"]["jwt_secret"]
    except Exception:
        if "_dev_jwt_secret" not in st.session_state:
            st.session_state["_dev_jwt_secret"] = _secrets.token_hex(32)
        return st.session_state["_dev_jwt_secret"]


def _token_hours() -> int:
    try:
        return int(st.secrets["auth"]["token_hours"])
    except Exception:
        return 12


# ── Database ────────────────────────────────────────────────────────────────
def _conn() -> sqlite3.Connection:
    c = sqlite3.connect(DB_PATH)
    c.row_factory = sqlite3.Row
    return c


def init_db() -> None:
    with _conn() as c:
        c.execute("""
            CREATE TABLE IF NOT EXISTS users (
                id            INTEGER PRIMARY KEY AUTOINCREMENT,
                username      TEXT UNIQUE NOT NULL COLLATE NOCASE,
                email         TEXT UNIQUE NOT NULL COLLATE NOCASE,
                password_hash TEXT NOT NULL,
                created_at    TEXT NOT NULL
            )
        """)
        c.execute("""
            CREATE TABLE IF NOT EXISTS resets (
                email      TEXT NOT NULL COLLATE NOCASE,
                code       TEXT NOT NULL,
                expires_at TEXT NOT NULL
            )
        """)
    _seed_demo_admin()


def _seed_demo_admin() -> None:
    """Create a throwaway admin on first run so the app is testable immediately.
    DELETE THIS in production (or just remove the user from users.db)."""
    with _conn() as c:
        n = c.execute("SELECT COUNT(*) AS n FROM users").fetchone()["n"]
        if n == 0:
            c.execute(
                "INSERT INTO users (username, email, password_hash, created_at) "
                "VALUES (?,?,?,?)",
                ("admin", "admin@dominate3.ai",
                 _hash_pw("Dominate3AI!"), _now_iso()),
            )


# ── Helpers ─────────────────────────────────────────────────────────────────
def _now() -> datetime:
    return datetime.now(timezone.utc)


def _now_iso() -> str:
    return _now().isoformat()


def _hash_pw(pw: str) -> str:
    # bcrypt caps at 72 bytes; signup enforces a max length below that.
    return bcrypt.hashpw(pw.encode("utf-8"), bcrypt.gensalt()).decode("utf-8")


def _verify_pw(pw: str, hashed: str) -> bool:
    try:
        return bcrypt.checkpw(pw.encode("utf-8"), hashed.encode("utf-8"))
    except Exception:
        return False


# ── JWT ─────────────────────────────────────────────────────────────────────
def create_token(username: str) -> str:
    now = _now()
    payload = {
        "sub": username,
        "iat": int(now.timestamp()),
        "exp": int((now + timedelta(hours=_token_hours())).timestamp()),
    }
    return jwt.encode(payload, _jwt_secret(), algorithm=ALGO)


def decode_token(token: str):
    """Return the payload dict if valid + unexpired, else None."""
    try:
        return jwt.decode(token, _jwt_secret(), algorithms=[ALGO])
    except jwt.ExpiredSignatureError:
        return None
    except jwt.InvalidTokenError:
        return None


# ── User operations ─────────────────────────────────────────────────────────
def register_user(username: str, email: str, password: str) -> tuple[bool, str]:
    username = (username or "").strip()
    email = (email or "").strip()

    if not username or not email or not password:
        return False, "All fields are required."
    if not (3 <= len(username) <= 32):
        return False, "Username must be 3–32 characters."
    if not EMAIL_RE.match(email):
        return False, "Enter a valid email address."
    ok, why = _password_ok(password)
    if not ok:
        return False, why
    try:
        with _conn() as c:
            c.execute(
                "INSERT INTO users (username, email, password_hash, created_at) "
                "VALUES (?,?,?,?)",
                (username, email, _hash_pw(password), _now_iso()),
            )
        return True, "Account created. You can sign in now."
    except sqlite3.IntegrityError:
        return False, "That username or email is already registered."


def authenticate(username: str, password: str) -> tuple[bool, str]:
    with _conn() as c:
        row = c.execute(
            "SELECT password_hash FROM users WHERE username = ?",
            ((username or "").strip(),),
        ).fetchone()
    if row and _verify_pw(password, row["password_hash"]):
        return True, "ok"
    return False, "Invalid username or password."


def _password_ok(pw: str) -> tuple[bool, str]:
    if len(pw) < 8:
        return False, "Password must be at least 8 characters."
    if len(pw) > 64:
        return False, "Password must be 64 characters or fewer."
    if not re.search(r"[A-Za-z]", pw) or not re.search(r"\d", pw):
        return False, "Password must contain at least one letter and one number."
    return True, ""


# ── Password reset (code emailed via existing SMTP secrets) ─────────────────
def start_reset(email: str) -> tuple[bool, str]:
    email = (email or "").strip()
    if not EMAIL_RE.match(email):
        return False, "Enter a valid email address."
    with _conn() as c:
        row = c.execute("SELECT username FROM users WHERE email = ?", (email,)).fetchone()
        # Always behave the same way to avoid leaking which emails are registered.
        if not row:
            return True, "If that email is registered, a reset code has been sent."
        code = f"{_secrets.randbelow(1000000):06d}"
        expires = (_now() + timedelta(minutes=15)).isoformat()
        c.execute("DELETE FROM resets WHERE email = ?", (email,))
        c.execute("INSERT INTO resets (email, code, expires_at) VALUES (?,?,?)",
                  (email, code, expires))
    sent, msg = _email_reset_code(email, code)
    if not sent:
        # SMTP not configured / failed — surface the code so dev flow still works.
        return True, f"(Email not sent: {msg}) Dev reset code: {code}"
    return True, "If that email is registered, a reset code has been sent."


def complete_reset(email: str, code: str, new_pw: str) -> tuple[bool, str]:
    email = (email or "").strip()
    ok, why = _password_ok(new_pw)
    if not ok:
        return False, why
    with _conn() as c:
        row = c.execute(
            "SELECT code, expires_at FROM resets WHERE email = ?", (email,)
        ).fetchone()
        if not row or row["code"] != (code or "").strip():
            return False, "Invalid or expired reset code."
        if datetime.fromisoformat(row["expires_at"]) < _now():
            c.execute("DELETE FROM resets WHERE email = ?", (email,))
            return False, "Reset code has expired. Request a new one."
        c.execute("UPDATE users SET password_hash = ? WHERE email = ?",
                  (_hash_pw(new_pw), email))
        c.execute("DELETE FROM resets WHERE email = ?", (email,))
    return True, "Password updated. You can sign in with your new password."


def _email_reset_code(email: str, code: str) -> tuple[bool, str]:
    import smtplib
    import ssl
    from email.mime.text import MIMEText
    try:
        cfg = st.secrets["email"]
    except Exception:
        return False, "email secrets not configured"
    try:
        host = str(cfg["smtp_server"]).strip()
        port = int(cfg.get("smtp_port", 587))
        sender = str(cfg["sender"]).strip()
        username = str(cfg.get("username", sender)).strip()
        # Gmail app passwords are shown in 4 space-separated groups; strip any
        # whitespace so a pasted-with-spaces password still authenticates.
        password = "".join(str(cfg.get("app_password", "")).split())
        timeout = int(cfg.get("timeout", 30))
        security = str(cfg.get("security", "")).strip().lower()
        if not security:
            security = "ssl" if port == 465 else "starttls"

        body = (f"Your DOMINATE 3AI password reset code is: {code}\n\n"
                f"This code expires in 15 minutes.\n\n"
                f"— ABP Communications LLC")
        msg = MIMEText(body, "plain", "utf-8")
        msg["From"] = sender
        msg["To"] = email
        msg["Subject"] = "DOMINATE 3AI — Password Reset Code"

        if security == "ssl":
            server = smtplib.SMTP_SSL(host, port, timeout=timeout,
                                      context=ssl.create_default_context())
        else:
            server = smtplib.SMTP(host, port, timeout=timeout)
            server.ehlo()
            if security in ("starttls", "tls"):
                server.starttls(context=ssl.create_default_context())
                server.ehlo()
        if password:
            server.login(username, password)
        server.sendmail(sender, email, msg.as_string())
        server.quit()
        return True, "sent"
    except Exception as e:
        return False, str(e)


# ── Cookie helpers ──────────────────────────────────────────────────────────
def _cookie_manager():
    """One CookieManager per session, stored in session_state.

    It must NOT be wrapped in @st.cache_resource: instantiating a CookieManager
    runs a widget command (getAll), and Streamlit raises CachedWidgetWarning for
    widget commands inside cached functions. A session_state singleton also keeps
    us from creating the same-keyed component twice in one run (DuplicateWidgetID).
    """
    if not _HAS_COOKIES:
        return None
    if "_cookie_mgr" not in st.session_state:
        st.session_state["_cookie_mgr"] = stx.CookieManager(key="d3ai_cookie_mgr")
    return st.session_state["_cookie_mgr"]


def _set_cookie(token: str) -> None:
    if not _HAS_COOKIES:
        return
    cm = _cookie_manager()
    expires = _now() + timedelta(hours=_token_hours())
    cm.set(COOKIE_NAME, token, expires_at=expires, key="set_d3ai_token")


def _get_cookie_token():
    if not _HAS_COOKIES:
        return None
    cm = _cookie_manager()
    try:
        return cm.get(COOKIE_NAME)
    except Exception:
        return None


def _clear_cookie() -> None:
    if not _HAS_COOKIES:
        return
    cm = _cookie_manager()
    try:
        cm.delete(COOKIE_NAME, key="del_d3ai_token")
    except Exception:
        pass


# ── Public gate API ─────────────────────────────────────────────────────────
def current_user():
    return st.session_state.get("auth_user")


def require_auth():
    """Return the username if authenticated, else None. Bootstraps from cookie."""
    init_db()
    if st.session_state.get("auth_user"):
        return st.session_state["auth_user"]
    token = _get_cookie_token()
    if token:
        payload = decode_token(token)
        if payload and payload.get("sub"):
            st.session_state["auth_user"] = payload["sub"]
            return payload["sub"]
    return None


def logout() -> None:
    st.session_state.pop("auth_user", None)
    _clear_cookie()
    st.rerun()


def _do_login(username: str, token: str) -> None:
    st.session_state["auth_user"] = username
    _set_cookie(token)
    st.rerun()


# ── Login / Sign-up / Reset UI ──────────────────────────────────────────────
_LOGIN_CSS = (
    "<style>"
    ".auth-logo-img{display:block;width:100%;max-width:300px;margin:0 auto 2px;"
    "border-radius:8px;box-shadow:0 6px 22px rgba(0,0,0,0.35);}"
    ".auth-logo{font-family:'Syne',sans-serif;font-size:2.1rem;font-weight:800;"
    "color:#fff;letter-spacing:0.04em;text-align:center;margin:0;}"
    ".auth-logo .g{color:#C8960C;}"
    ".auth-tag{text-align:center;font-size:10px;color:rgba(255,255,255,0.4);"
    "letter-spacing:0.22em;text-transform:uppercase;margin:6px 0 4px;}"
    ".auth-sub{text-align:center;font-size:12px;color:rgba(255,255,255,0.45);"
    "margin:0 0 18px;}"
    ".auth-rule{height:1px;background:linear-gradient(90deg,transparent,"
    "rgba(200,150,12,0.4),transparent);margin:14px 0 18px;}"
    "</style>"
)


def render_login() -> None:
    """Full login experience: centered logo on top, Sign In form, and
    Sign Up / Forgot Password options below it."""
    init_db()
    st.markdown(_LOGIN_CSS, unsafe_allow_html=True)

    mode = st.session_state.get("auth_mode", "signin")
    _, mid, _ = st.columns([1, 1.5, 1])

    with mid:
        # ── Logo on top of the login section ──────────────────────────────
        _logo = get_logo_data_uri()
        _logo_html = (
            f'<img src="{_logo}" alt="DOMINATE 3AI" class="auth-logo-img"/>'
            if _logo else
            '<div class="auth-logo">DOMINATE <span class="g">3AI</span></div>'
        )
        st.markdown(
            _logo_html
            + '<div class="auth-tag">One Platform · Total Solutions · Total Success</div>'
            '<div class="auth-rule"></div>',
            unsafe_allow_html=True,
        )

        if mode == "signin":
            _render_signin()
        elif mode == "signup":
            _render_signup()
        elif mode == "forgot":
            _render_forgot()


def _switch(mode: str) -> None:
    st.session_state["auth_mode"] = mode
    st.rerun()


def _render_signin() -> None:
    st.markdown('<div class="auth-sub">Sign in to your intelligence console</div>',
                unsafe_allow_html=True)

    # simple lockout after repeated failures (per session)
    fails = st.session_state.get("login_fails", 0)

    with st.form("signin_form", clear_on_submit=False):
        username = st.text_input("Username", placeholder="your username")
        password = st.text_input("Password", type="password", placeholder="••••••••")
        submitted = st.form_submit_button("Sign In", type="primary",
                                          use_container_width=True)

    if submitted:
        if fails >= 5:
            st.error("Too many failed attempts. Refresh the page and try again.")
            return
        ok, msg = authenticate(username, password)
        if ok:
            st.session_state["login_fails"] = 0
            _do_login(username.strip(), create_token(username.strip()))
        else:
            st.session_state["login_fails"] = fails + 1
            st.error(msg)

    # ── Sign Up + Forgot Password, below the login section ────────────────
    st.markdown('<div class="auth-rule"></div>', unsafe_allow_html=True)
    b1, b2 = st.columns(2)
    with b1:
        if st.button("Create account", use_container_width=True, key="go_signup"):
            _switch("signup")
    with b2:
        if st.button("Forgot password?", use_container_width=True, key="go_forgot"):
            _switch("forgot")


def _render_signup() -> None:
    st.markdown('<div class="auth-sub">Create your DOMINATE 3AI account</div>',
                unsafe_allow_html=True)
    with st.form("signup_form", clear_on_submit=False):
        username = st.text_input("Username", placeholder="3–32 characters")
        email = st.text_input("Email", placeholder="name@company.com")
        pw = st.text_input("Password", type="password",
                           placeholder="8+ chars, letters & numbers")
        pw2 = st.text_input("Confirm password", type="password",
                            placeholder="re-enter password")
        submitted = st.form_submit_button("Create Account", type="primary",
                                          use_container_width=True)
    if submitted:
        if pw != pw2:
            st.error("Passwords do not match.")
        else:
            ok, msg = register_user(username, email, pw)
            (st.success if ok else st.error)(msg)
            if ok:
                _switch("signin")

    if st.button("← Back to sign in", use_container_width=True, key="back_1"):
        _switch("signin")


def _render_forgot() -> None:
    st.markdown('<div class="auth-sub">Reset your password</div>',
                unsafe_allow_html=True)
    stage = st.session_state.get("reset_stage", "request")

    if stage == "request":
        with st.form("reset_req", clear_on_submit=False):
            email = st.text_input("Account email", placeholder="name@company.com")
            submitted = st.form_submit_button("Send Reset Code", type="primary",
                                              use_container_width=True)
        if submitted:
            ok, msg = start_reset(email)
            (st.info if ok else st.error)(msg)
            if ok:
                st.session_state["reset_email"] = email.strip()
                st.session_state["reset_stage"] = "verify"
                st.rerun()
    else:
        st.caption(f"Code sent to {st.session_state.get('reset_email', 'your email')}")
        with st.form("reset_done", clear_on_submit=False):
            code = st.text_input("6-digit reset code", placeholder="123456")
            pw = st.text_input("New password", type="password",
                               placeholder="8+ chars, letters & numbers")
            pw2 = st.text_input("Confirm new password", type="password")
            submitted = st.form_submit_button("Update Password", type="primary",
                                              use_container_width=True)
        if submitted:
            if pw != pw2:
                st.error("Passwords do not match.")
            else:
                ok, msg = complete_reset(
                    st.session_state.get("reset_email", ""), code, pw)
                (st.success if ok else st.error)(msg)
                if ok:
                    st.session_state.pop("reset_stage", None)
                    st.session_state.pop("reset_email", None)
                    _switch("signin")

    if st.button("← Back to sign in", use_container_width=True, key="back_2"):
        st.session_state.pop("reset_stage", None)
        _switch("signin")
